import "./App.css";
import Navbar from "./Components/Navbar";
import Main from "./Components/Main";
import Menu from "./Components/pages/Menu";
import Testimonials from "./Components/Testimonials";
import Footer from "./Components/Footer";

function App() {
  return (
    <>
      <Navbar />
      <Main />
      <Menu />
      <Testimonials />
      <Footer />
    </>
  );
}
export default App;
